function firstUnique(s) {
  const m = new Map();
  for (const c of s) m.set(c, (m.get(c) || 0) + 1);
  for (let i = 0; i < s.length; i++) {
    if (m.get(s[i]) === 1) return i;
  }
  return -1;
}

tests:
if (firstUnique('leetcode') !== 0) throw new Error('leetcode -> 0');
if (firstUnique('loveleetcode') !== 2) throw new Error('loveleetcode -> 2');
if (firstUnique('aabb') !== -1) throw new Error('aabb -> -1');
if (firstUnique('') !== -1) throw new Error('empty -> -1');

