function twoSum(nums, target) {
  let i = 0, j = nums.length - 1;
  while (i < j) {
    const s = nums[i] + nums[j];
    if (s === target) return [i, j];
    if (s < target) i++;
    else j--;
  }
  return [];
}

tests:
if (JSON.stringify(twoSum([1, 2, 4, 11, 15], 15)) !== '[2,3]') throw new Error('sum 15 -> [2,3]');
if (JSON.stringify(twoSum([1, 2, 4, 11, 15], 3)) !== '[0,1]') throw new Error('sum 3 -> [0,1]');
if (JSON.stringify(twoSum([1, 2, 4], 100)) !== '[]') throw new Error('no pair -> []');

