solution:
function maxSumK(arr, k) {
  let s = 0;
  for (let i = 0; i < k; i++) s += arr[i];
  let best = s;
  for (let i = k; i < arr.length; i++) {
    s += arr[i] - arr[i - k];
    best = Math.max(best, s);
  }
  return best;
}

tests:
if (maxSumK([2, 1, 5, 1, 3, 2], 3) !== 9) throw new Error('expected 9');
if (maxSumK([1, 2, 3], 3) !== 6) throw new Error('whole array -> 6');
if (maxSumK([4, -1, 2, 1], 2) !== 3) throw new Error('expected 3');

