solution:
function insertPos(arr, target) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

tests:
if (insertPos([1, 3, 5, 6], 5) !== 2) throw new Error('5 -> 2');
if (insertPos([1, 3, 5, 6], 2) !== 1) throw new Error('2 -> 1');
if (insertPos([1, 3, 5, 6], 7) !== 4) throw new Error('7 -> 4');
if (insertPos([1, 3, 5, 6], 0) !== 0) throw new Error('0 -> 0');
if (insertPos([], 1) !== 0) throw new Error('empty -> 0');

