solution:
function rangeSums(arr, queries) {
  const pre = [0];
  for (let i = 0; i < arr.length; i++) pre.push(pre[i] + arr[i]);
  return queries.map(([l, r]) => pre[r + 1] - pre[l]);
}

tests:
const out = rangeSums([1, 2, 3, 4, 5], [[0, 2], [1, 3], [0, 4], [2, 2]]);
if (JSON.stringify(out) !== '[6,9,15,3]') throw new Error('got ' + JSON.stringify(out));
if (JSON.stringify(rangeSums([10], [[0, 0]])) !== '[10]') throw new Error('single -> [10]');
